/* PasstheEPPP — Question Bank Batch 20
   Enhanced rationale format — 80 new questions across all 8 domains */
(function(){
    if (typeof EPPPData === 'undefined') return;

    const batch20 = [
        // ===== Domain 1: Biological Bases (10) =====
        {domainId:1, q:"The default mode network (DMN) is most active during:", options:["Focused external cognitive environmental task attention","Mind-wandering, self-referential thought, and daydreaming","Intense sustained demanding physical aerobic endurance exercise","Rapid eye movement sleep uniquely exclusively at night"], answer:1, difficulty:"hard", rationale:"Correct: (B) The DMN (medial PFC, posterior cingulate, precuneus, angular gyrus) activates during rest, introspection, autobiographical memory retrieval, future planning, and social cognition. It deactivates during goal-directed tasks.\n\nWhy others are wrong:\n(A) Focused external attention DEACTIVATES the DMN — the task-positive network activates instead\n(C) Intense exercise engages motor and cardiovascular systems — DMN activity decreases during demanding tasks\n(D) While DMN-related activity occurs in REM, it's most consistently documented during waking rest states"},
        {domainId:1, q:"Glutamate is the brain's primary:", options:["Inhibitory neurotransmitter","Excitatory neurotransmitter","Endocrine systemic hormone","Fundamental structural protein"], answer:1, difficulty:"easy", rationale:"Correct: (B) Glutamate is the most abundant excitatory neurotransmitter in the CNS, involved in ~90% of excitatory synaptic transmission. Critical for learning, memory (LTP), and neural development. Excess glutamate is neurotoxic (excitotoxicity).\n\nWhy others are wrong:\n(A) The primary inhibitory neurotransmitter is GABA\n(C) Glutamate is a neurotransmitter, not a hormone (though the distinction isn't always absolute)\n(D) Glutamate is a chemical messenger, not a structural protein"},
        {domainId:1, q:"Broca's aphasia is characterized by:", options:["Fluent rapid receptive speech with profound poor language comprehension","Non-fluent, effortful, telegraphic speech with relatively preserved comprehension","Perfectly normal pragmatic semantic speech maintained in all specific situations","Exclusively severe profound localized progressive writing mechanical deficits"], answer:1, difficulty:"easy", rationale:"Correct: (B) Broca's aphasia (expressive/non-fluent): speech is slow, halting, effortful, and agrammatic ('want...water'). Comprehension is relatively preserved. Patients are typically aware of and frustrated by their deficit.\n\nWhy others are wrong:\n(A) Fluent speech with poor comprehension = Wernicke's aphasia (receptive)\n(C) Broca's aphasia involves significant speech production deficits\n(D) While writing may also be impaired, the hallmark is impaired verbal expression"},
        {domainId:1, q:"The sympathetic nervous system's fight-or-flight response includes:", options:["Systematically decreased resting heart rate and highly constricted visual pupils","Increased heart rate, dilated pupils, bronchodilation, and blood flow to muscles","Significantly increased active gastrointestinal systemic metabolic digestion","Significantly persistently decreased total structural systemic blood pressure"], answer:1, difficulty:"easy", rationale:"Correct: (B) Sympathetic activation prepares for emergency: increased heart rate, dilated pupils, bronchodilation (more air), blood diverted to skeletal muscles, glycogen → glucose release, adrenal epinephrine secretion.\n\nWhy others are wrong:\n(A) Decreased heart rate and constricted pupils = parasympathetic ('rest and digest') responses\n(C) Increased digestion = parasympathetic activity — sympathetic activation INHIBITS digestion\n(D) Sympathetic activation INCREASES blood pressure to support emergency response"},
        {domainId:1, q:"Melatonin, produced by the pineal gland, is important for:", options:["Systematic physiological fight-or-flight stress response","Circadian rhythm regulation and sleep-wake cycle timing","Voluntary procedural coordinated physical muscle contraction","Conscious subjective structural psychological pain perception"], answer:1, difficulty:"easy", rationale:"Correct: (B) Melatonin: produced by the pineal gland in response to darkness. It signals the biological clock (suprachiasmatic nucleus) to promote sleepiness. Suppressed by light exposure, especially blue light.\n\nWhy others are wrong:\n(A) Stress response → cortisol (HPA axis) and epinephrine/norepinephrine (sympathetic NS)\n(C) Muscle contraction → acetylcholine at the neuromuscular junction\n(D) Pain perception → substance P, glutamate, endorphins — not melatonin"},
        {domainId:1, q:"The superior colliculus is responsible for:", options:["Basic foundational temporal auditory processing","Visual reflexes and eye movement coordination","Complex semantic expressive language production","Systematic episodic declarative memory consolidation"], answer:1, difficulty:"hard", rationale:"Correct: (B) Superior colliculus (midbrain tectum): coordinates visual reflexes (orienting toward visual stimuli), saccadic eye movements, and integration of visual, auditory, and somatosensory information for head/eye orientation.\n\nWhy others are wrong:\n(A) Auditory processing → inferior colliculus (midbrain) and auditory cortex (temporal lobe)\n(C) Language production → Broca's area (left frontal lobe)\n(D) Memory consolidation → hippocampus"},
        {domainId:1, q:"Multiple sclerosis (MS) is caused by:", options:["Pathological systemic massive overproduction and explicit dopamine excess","Autoimmune demyelination — the immune system attacks myelin sheaths in the CNS","Severe chronic pervasive structural specific cortical serotonin deficiency","Aggressive fast-acting pervasive biological bacterial infection of the brain"], answer:1, difficulty:"medium", rationale:"Correct: (B) MS: the immune system attacks oligodendrocyte-produced myelin in the CNS, creating lesions (plaques) that disrupt signal transmission. Symptoms: vision problems, motor weakness, fatigue, sensory disturbances; relapsing-remitting course common.\n\nWhy others are wrong:\n(A) Dopamine excess is associated with psychotic symptoms, not MS\n(C) Serotonin deficiency is linked to depression, not MS\n(D) MS is autoimmune, not caused by bacterial infection (though infections may trigger flare-ups)"},
        {domainId:1, q:"The prefrontal cortex undergoes significant development through:", options:["Exclusively during early infancy, strictly restricted from birth to age two only","Adulthood — particularly through adolescence, with myelination continuing into mid-20s","It is considered entirely completely physically structurally developed precisely at birth","Exclusively strictly restricted to the highly sensitive early prenatal fetal development"], answer:1, difficulty:"medium", rationale:"Correct: (B) The PFC is one of the LAST brain regions to fully mature. Synaptic pruning, myelination, and connectivity refinement continue through adolescence into the mid-20s, explaining adolescent risk-taking and impulsivity.\n\nWhy others are wrong:\n(A) PFC development extends FAR beyond age 2\n(C) The PFC is among the LEAST mature brain regions at birth\n(D) PFC development extends well beyond fetal development through adolescence"},
        {domainId:1, q:"The insula is involved in:", options:["Exclusively strictly uniquely restricted to deliberate physical motor control","Interoception, emotional awareness, empathy, disgust, and pain processing","Exclusively entirely strictly restricted to primary chemical sensory olfaction","Exclusively uniquely localized specifically solely for primary peripheral vision"], answer:1, difficulty:"hard", rationale:"Correct: (B) The insula processes interoceptive signals (body state awareness), subjective feeling states, empathy, disgust, pain, taste, and risk/uncertainty evaluation. It bridges bodily sensation with emotional experience.\n\nWhy others are wrong:\n(A) Motor control → motor cortex, basal ganglia, cerebellum\n(C) Olfaction → piriform cortex and orbitofrontal cortex (though the insula does process taste)\n(D) Vision → occipital lobe"},
        {domainId:1, q:"Lithium is the first-line treatment for:", options:["Attention deficit hyperactivity disorder with significant impulsivity","Bipolar disorder (mood stabilization for manic and depressive episodes)","Schizophrenia spectrum conditions displaying active psychotic features","Specific phobia featuring highly intense immediate physiological arousal"], answer:1, difficulty:"easy", rationale:"Correct: (B) Lithium: the gold standard mood stabilizer for bipolar disorder. Effective for mania prevention and treatment, reduces suicide risk. Requires blood level monitoring (narrow therapeutic window: 0.6-1.2 mEq/L) and thyroid/renal monitoring.\n\nWhy others are wrong:\n(A) ADHD → stimulant medications (methylphenidate, amphetamine)\n(C) Schizophrenia → antipsychotic medications (typical and atypical)\n(D) Specific phobia → exposure therapy (in vivo exposure), not medication as first-line"},

        // ===== Domain 2: Cognitive-Affective (10) =====
        {domainId:2, q:"The testing effect (retrieval practice) demonstrates that:", options:["Testing only functions strictly as an objective standardized measurement of baseline learning","Actively retrieving information from memory strengthens retention MORE than additional studying","Participating in frequent repeated testing actually systematically permanently impairs memory","Only utilizing highly specific standardized multiple-choice tests can broadly improve memory"], answer:1, difficulty:"medium", rationale:"Correct: (B) Roediger & Karpicke: the act of RETRIEVING information from memory (testing) strengthens memory traces more than re-reading or re-studying. This is one of the most robust and practically important findings in cognitive psychology.\n\nWhy others are wrong:\n(A) Testing doesn't just MEASURE — it ENHANCES learning (a direct learning tool)\n(C) Testing STRENGTHENS memory, not impairs it\n(D) Multiple formats (free recall, short answer, flashcards) produce the testing effect — not just multiple-choice"},
        {domainId:2, q:"Baddeley's model of working memory includes:", options:["Only a single undifferentiated temporary short-term informational capacity storage buffer","The phonological loop, visuospatial sketchpad, central executive, and episodic buffer","An entirely completely unlimited expansive capacity for simultaneous cognitive processing","Only fully consolidated stable permanent structural long-term semantic memory components"], answer:1, difficulty:"medium", rationale:"Correct: (B) Baddeley & Hitch (1974, updated 2000): working memory has four components — phonological loop (verbal), visuospatial sketchpad (visual/spatial), central executive (attention controller), and episodic buffer (integrates information from multiple sources).\n\nWhy others are wrong:\n(A) Baddeley proposed MULTIPLE subsystems, not a single buffer\n(C) Working memory has LIMITED capacity (7 ± 2 items, or about 4 chunks)\n(D) Working memory is distinct from long-term memory — it temporarily maintains and manipulates information"},
        {domainId:2, q:"Peak-end rule (Kahneman) states that:", options:["People systematically evaluate experiences equally across every single temporal moment","People evaluate experiences based primarily on the INTENSE peak and the ultimate ENDING","Endings are fundamentally completely clinically irrelevant to ultimate experience evaluation","Only explicitly intense positive peaks are consciously remembered after the experience ends"], answer:1, difficulty:"hard", rationale:"Correct: (B) Kahneman: retrospective evaluation of experiences is disproportionately influenced by two moments — the peak intensity (best or worst moment) and the end. Duration plays a surprisingly small role (duration neglect).\n\nWhy others are wrong:\n(A) Moment-by-moment evaluation is how the 'experiencing self' works, but the 'remembering self' uses peak-end\n(C) Endings are CRUCIAL — a good ending can improve evaluation of an otherwise unpleasant experience\n(D) Both positive and negative peaks influence evaluation"},
        {domainId:2, q:"Semantic memory refers to:", options:["Autobiographical episodic memory strictly for highly specific personal life history events","General knowledge about the world, facts, concepts, and language independent of personal context","Implicit procedural nondeclarative motor skill memory developed over repeated active practice","Temporary transient sensory iconic and echoic memory trace duration lasting mere milliseconds"], answer:1, difficulty:"easy", rationale:"Correct: (B) Semantic memory (Tulving): organized knowledge about the world — facts, concepts, word meanings, and general knowledge. It's decontextualized (you know Paris is the capital of France without remembering WHEN you learned it).\n\nWhy others are wrong:\n(A) Memory for personal events = episodic memory (autobiographical, contextualized)\n(C) Motor skill memory = procedural memory (implicit/non-declarative)\n(D) Millisecond sensory memory = sensory register (iconic for visual, echoic for auditory)"},
        {domainId:2, q:"Decision fatigue refers to:", options:["Systematically continuously optimized accurate decision-making following multiple decisions","Deteriorating decision quality after making many decisions, causing impulsivity or avoidance","Severe cognitive resource fatigue exclusively resulting strictly from physical motor decisions","A consistently universally robust pleasant enjoyable experience during the decision process"], answer:1, difficulty:"medium", rationale:"Correct: (B) Decision fatigue: cognitive resource depletion from repeated decision-making leads to poorer choices (impulsive or avoidant). Related to ego depletion theory. Explains why parole boards grant fewer paroles later in the day.\n\nWhy others are wrong:\n(A) Decision quality DECREASES with more decisions, not improves\n(C) Decision fatigue applies to ALL types of decisions — mental, social, consumer, judicial\n(D) Decision fatigue is aversive, not enjoyable"},
        {domainId:2, q:"Source monitoring errors occur when:", options:["People perfectly accurately flawlessly identify exactly where they learned semantic information","People fundamentally misattribute the specific original SOURCE or context of a stored memory","Exclusively only young developing children frequently consistently make these specific errors","Information sources are universally always accurately strictly correctly correctly identified"], answer:1, difficulty:"medium", rationale:"Correct: (B) Source monitoring (Johnson et al.): errors in identifying WHERE or HOW information was acquired. Examples: false memories from imagination inflation, cryptomnesia (unconscious plagiarism), confusing dreams with reality.\n\nWhy others are wrong:\n(A) Source monitoring errors specifically involve IMPERFECT source identification\n(C) Adults also make source monitoring errors — they're especially common in older adults and certain clinical conditions\n(D) Source misattribution is common and well-documented"},
        {domainId:2, q:"The weapons focus effect in eyewitness testimony refers to:", options:["Systematically improved overall memory capacity for all sensory details during threatening events","Eyewitnesses intensely focusing on a weapon, which IMPAIRS memory for other peripheral details","Witnesses universally always flawlessly and accurately identifying the specific correct weapon","The highly unusually low frequency of actual visible weapons appearing within true crime scenes"], answer:1, difficulty:"medium", rationale:"Correct: (B) Weapons focus (Loftus): the presence of a weapon narrows attention to the threat object, reducing encoding of peripheral details like the perpetrator's appearance. This leads to WORSE facial identification.\n\nWhy others are wrong:\n(A) Weapon focus IMPAIRS overall detail memory by narrowing attention\n(C) Witnesses may accurately recall the weapon but POORLY recall the perpetrator\n(D) The effect is about the IMPACT of weapons on attention and memory, not their frequency"},
        {domainId:2, q:"The availability heuristic leads people to:", options:["Carefully strictly explicitly and accurately objectively calculate standard statistical base rates","Estimate likelihood based on how easily examples come to mind, overestimating vivid recent events","Always consistently reliably make highly accurate objective generalized probability judgments","Completely deliberately ignore all explicitly freely universally available statistical information"], answer:1, difficulty:"easy", rationale:"Correct: (B) Tversky & Kahneman: availability heuristic — frequency/probability judgments are biased by how easily instances can be retrieved. Vivid, recent, or emotionally charged events are overestimated (shark attacks, plane crashes).\n\nWhy others are wrong:\n(A) The availability heuristic BYPASSES base rate calculation — that's why it produces errors\n(C) The heuristic produces SYSTEMATIC biases, not accuracy\n(D) People use available (easily recalled) information — they don't ignore it"},
        {domainId:2, q:"Prospective memory involves:", options:["Accurately consciously explicitly remembering highly specific distant personal historical events","Actively remembering to successfully carry out specific intended scheduled actions in the future","Exclusively utilizing active implicit automatic nondeclarative procedural physical motor skills","Relying exclusively solely on deeply entirely completely unconscious internal memory processes"], answer:1, difficulty:"easy", rationale:"Correct: (B) Prospective memory: remembering to do something in the future at the right time or in the right context. Time-based (take pill at 3 PM) and event-based (give message when seeing someone). Declines with age.\n\nWhy others are wrong:\n(A) Remembering past events = retrospective memory\n(C) Procedural skills = implicit/non-declarative memory\n(D) Prospective memory involves both conscious intention-setting and automatic retrieval cues"},
        {domainId:2, q:"The representativeness heuristic leads to errors when:", options:["People systematically correctly universally apply appropriate base rates across all situations","People erroneously judge probability based on similarity to a prototype rather than base rates","People systematically exclusively apply formal rigid algorithmic logic for all daily decisions","People completely fully actively deliberately entirely avoid utilizing any cognitive shortcuts"], answer:1, difficulty:"medium", rationale:"Correct: (B) Representativeness heuristic (Kahneman & Tversky): judging probability by resemblance to a category prototype. This ignores base rates, sample size, and regression to the mean (e.g., the 'Linda problem' — conjunction fallacy).\n\nWhy others are wrong:\n(A) The error specifically occurs because people IGNORE base rates\n(C) Heuristics ARE shortcuts that replace algorithms — the representativeness heuristic is a cognitive shortcut\n(D) People commonly use heuristics — avoiding all shortcuts is rare and impractical"},

        // ===== Domain 3: Social & Cultural (10) =====
        {domainId:3, q:"The elaboration likelihood model (ELM, Petty & Cacioppo) proposes:", options:["Only one single exclusive route to achieving profound lasting cognitive persuasion","Two routes: central (careful evaluation) and peripheral (superficial cue reliance)","Authentic long-term cognitive persuasion is fundamentally completely impossible","Logical structured arguments never matter during authentic interpersonal persuasion"], answer:1, difficulty:"medium", rationale:"Correct: (B) ELM: central route — high motivation/ability → careful, thoughtful evaluation of argument quality → durable attitude change. Peripheral route — low motivation/ability → reliance on superficial cues → temporary change.\n\nWhy others are wrong:\n(A) Two routes exist, not one — and which is used depends on motivation and ability\n(C) Persuasion is well-documented and predictable under the right conditions\n(D) Arguments matter greatly in the CENTRAL route — when people are motivated to scrutinize"},
        {domainId:3, q:"Relative deprivation theory proposes that social unrest results from:", options:["Strictly measured absolute quantifiable poverty levels documented within the population","People's PERCEPTION that they are worse off compared to others, not objective conditions","Complete absolute psychological satisfaction with one's personal physical circumstances","Exclusively intense overwhelming historically driven macro-level external political forces"], answer:1, difficulty:"medium", rationale:"Correct: (B) Relative deprivation (Stouffer, Runciman): dissatisfaction arises from perceived discrepancy between what one HAS and what one EXPECTS to have (comparing to reference groups). Revolutions often occur when conditions are improving but expectations rise faster.\n\nWhy others are wrong:\n(A) ABSOLUTE poverty doesn't always predict unrest — PERCEIVED relative disadvantage does\n(C) Satisfaction would reduce social unrest, not create it\n(D) While politics matter, relative deprivation is a psychological/perceptual process within individuals"},
        {domainId:3, q:"Implicit bias differs from explicit bias in that implicit bias:", options:["Is always inherently permanently structurally far stronger than stated explicit bias","Operates AUTOMATICALLY and UNCONSCIOUSLY, often contradicting one's stated beliefs","Is purely theoretical and fundamentally does not exist within measurable modern reality","Can only currently be accurately reliably measured exclusively through self-report"], answer:1, difficulty:"medium", rationale:"Correct: (B) Implicit bias: automatic, unconscious associations (measured by IAT, priming tasks) that can diverge from consciously held beliefs. Someone who genuinely believes in equality may still hold implicit biases.\n\nWhy others are wrong:\n(A) Implicit and explicit biases can be independent — neither is always stronger\n(C) Extensive research documents the existence and effects of implicit biases\n(D) Implicit bias is specifically measured through INDIRECT methods (IAT, reaction time) — self-report captures EXPLICIT bias"},
        {domainId:3, q:"Social facilitation occurs when the presence of others:", options:["Consistently unequivocally universally impairs overall baseline task performance","ENHANCES performance on simple/well-learned tasks but IMPAIRS complex/novel tasks","Consistently demonstrates absolutely zero empirical measurable effect on performance","Exclusively strictly applies only to highly competitive organized team physical sports"], answer:1, difficulty:"medium", rationale:"Correct: (B) Zajonc (1965): others' presence increases arousal, which facilitates dominant responses. For simple/practiced tasks, the dominant response is correct → enhanced performance. For complex/new tasks, errors are dominant → impaired performance.\n\nWhy others are wrong:\n(A) Others' presence ENHANCES performance on simple tasks — it doesn't always impair\n(C) Social facilitation demonstrates significant effects on performance\n(D) Social facilitation has been documented across many settings (work, education, athletics, even cockroaches)"},
        {domainId:3, q:"Intergroup anxiety refers to:", options:["Intense pervasive clinical anxiety focused exclusively about one's own specific ingroup","Anxiety and threat experienced when anticipating interactions with outgroup members","A highly severe formal diagnosed clinical anxiety disorder requiring immediate treatment","Intense specific situational performance anxiety occurring during standardized group tests"], answer:1, difficulty:"medium", rationale:"Correct: (B) Intergroup anxiety (Stephan & Stephan): apprehension about cross-group interactions — fear of being embarrassed, rejected, or misunderstood. It can lead to avoidance of intergroup contact and increased prejudice.\n\nWhy others are wrong:\n(A) Intergroup anxiety is about interactions WITH outgroup members, not anxiety about one's own group\n(C) It's a normal social-psychological phenomenon, not a clinical disorder\n(D) Test anxiety is a separate construct related to evaluation apprehension"},
        {domainId:3, q:"Attribution theory (Heider, Weiner) examines how people:", options:["Superficially assign distinct physical sensory attributes systematically to daily objects","Explain the causes of behavior—attributing events to internal or external situational factors","Consistently inherently successfully reliably make perfectly accurate causal social judgments","Exclusively rigidly uniquely apply formal advanced statistical reasoning to social phenomena"], answer:1, difficulty:"easy", rationale:"Correct: (B) Attribution theory: how people explain causality. Heider distinguished internal (person) vs. external (situation). Weiner added dimensions: stability (stable/unstable), controllability, and locus — creating a 3-dimensional model of causal attribution.\n\nWhy others are wrong:\n(A) Attribution theory is about CAUSAL explanations for behavior, not physical attributes of objects\n(C) Attribution processes involve systematic BIASES (FAE, self-serving bias), not just accurate judgments\n(D) People use heuristics and biases, not exclusively statistical reasoning, in making attributions"},
        {domainId:3, q:"Conformity is REDUCED by:", options:["Systematically continuously actively increasing the total group size indefinitely","Having at least one ally or dissenter who explicitly definitively breaks unanimity","Deliberately structurally actively making the correct desired answer more ambiguous","Significantly directly aggressively increasing the overall prestige of the majority"], answer:1, difficulty:"easy", rationale:"Correct: (B) Asch: even ONE dissenter dramatically reduces conformity (from ~37% to ~5%). The ally need not give the correct answer — merely breaking unanimity empowers the participant to disagree.\n\nWhy others are wrong:\n(A) Conformity increases with group size but plateaus around 3-5 members\n(C) Increased ambiguity INCREASES reliance on others, which INCREASES conformity\n(D) Higher prestige of the majority INCREASES conformity (greater informational influence)"},
        {domainId:3, q:"Stereotype threat (Steele & Aronson) occurs when:", options:["Deep societal cultural societal stereotypes are consistently universally proven fully accurate","Awareness of negative stereotypes creates anxiety that impairs relevant task performance","Exclusively uniquely only specific minority groups systematically experience cognitive stress","Such psychological awareness has absolutely zero measurable empirical effect on performance"], answer:1, difficulty:"medium", rationale:"Correct: (B) Stereotype threat: when individuals are aware of negative stereotypes about their group, the anxiety of potentially confirming the stereotype consumes cognitive resources (working memory) and impairs performance on the stereotyped domain.\n\nWhy others are wrong:\n(A) Stereotypes are often inaccurate — and stereotype threat is about their PSYCHOLOGICAL IMPACT, not accuracy\n(C) Any group can experience stereotype threat when a relevant negative stereotype exists (e.g., white men in math vs. Asian men)\n(D) Stereotype threat has robust, documented effects on performance across many domains"},
        {domainId:3, q:"Cultural dimensions theory (Hofstede) includes:", options:["Only one single primary foundational dimension explaining global societal behavior","Multiple dimensions including individualism, power distance, and uncertainty avoidance","Strictly explicitly exclusively focused purely entirely upon standard Western cultural values","Universal behavioral developmental dimensions that are entirely biologically determined"], answer:1, difficulty:"medium", rationale:"Correct: (B) Hofstede's original four dimensions (later expanded to six): individualism-collectivism, power distance, uncertainty avoidance, masculinity-femininity, long-term orientation, and indulgence-restraint. Used to compare national cultures.\n\nWhy others are wrong:\n(A) Hofstede identified multiple dimensions, not just one\n(C) Hofstede studied cultures worldwide (originally 40+ countries with IBM employees)\n(D) Cultural dimensions are socially constructed and historically developed, not biologically determined"},
        {domainId:3, q:"The sleeper effect in persuasion occurs when:", options:["Overall message persuasion is fundamentally phenomenally strongest strictly immediately after the message","A message from a LOW-credibility source becomes MORE persuasive over time as the source is forgotten","Verbal cognitive persuasion fundamentally functionally never works durably over extended temporal periods","Exclusively strictly highly credible recognized expert sources produce any lasting durable attitude change"], answer:1, difficulty:"hard", rationale:"Correct: (B) Sleeper effect: initially discounted messages (from non-credible sources) gain persuasive power over time because the source-message association decays faster than the message content itself.\n\nWhy others are wrong:\n(A) The sleeper effect specifically describes persuasion that INCREASES over time, not strongest immediately\n(C) The sleeper effect demonstrates persuasion CAN work (and increase) over time\n(D) The sleeper effect shows that even low-credibility sources can produce lasting attitude change"},


        // ===== Domain 4: Growth & Lifespan (5) =====
        {domainId:4, q:"Goodness of fit (Thomas & Chess) refers to:", options:["Strictly uniquely defining exactly how well a developing child physically formally dresses","The match between a child's temperament and the demands/expectations of the environment","Exclusively explicitly focusing solely upon perfect rigid structural genetic compatibility","Strictly an abstract theoretical empirical statistical mathematical conceptual model only"], answer:1, difficulty:"medium", rationale:"Correct: (B) Thomas & Chess: developmental outcomes depend on how well the child's temperament matches environmental demands. A 'slow-to-warm-up' child does well with patient parents but may struggle with demanding, inflexible ones.\n\nWhy others are wrong:\n(A) 'Fit' refers to temperament-environment match, not clothing\n(C) Goodness of fit considers the interaction between temperament and environment, not just genetics\n(D) While used in statistics, in developmental psychology it's specifically about temperament-environment match"},
        {domainId:4, q:"Marcia's identity status of foreclosure involves:", options:["Successfully explicitly exploring diverse broad options and thoroughly making a commitment","Making a commitment WITHOUT having explored alternatives, adopting values without questioning","Demonstrating absolutely no commitment alongside vigorous intense active identity exploration","Demonstrating absolutely complete total lack of both final commitment and active exploration"], answer:1, difficulty:"medium", rationale:"Correct: (B) Foreclosure: commitment without exploration. The adolescent has 'foreclosed' on identity by accepting predetermined roles, values, or beliefs (often parental) without personally exploring alternatives.\n\nWhy others are wrong:\n(A) Exploration + commitment = identity achievement\n(C) No commitment + active exploration = moratorium\n(D) No commitment + no exploration = identity diffusion"},
        {domainId:4, q:"Resiliency research has identified protective factors including:", options:["Strictly exclusively focusing solely upon inherited biological hereditary immutable genetic advantages","Supportive relationships, internal locus of control, problem-solving skills, and community resources","Solely uniquely completely depending upon possessing an exceptionally statistically high baseline IQ score","The fundamental complete sustained absolute objective total permanent absence of any clear risk factors"], answer:1, difficulty:"medium", rationale:"Correct: (B) Resilience protective factors operate at multiple levels: individual (temperament, intelligence, self-efficacy), family (warm/supportive caregiver, stable environment), and community (school connection, prosocial peers, mentors).\n\nWhy others are wrong:\n(A) Resilience involves environmental AND individual factors — not just genetics\n(C) High IQ helps but is just one of many protective factors\n(D) Resilience is specifically about POSITIVE outcomes DESPITE risk exposure — not the absence of risk"},
        {domainId:4, q:"Permissive parenting (Baumrind) is characterized by:", options:["Demonstrating consistently extraordinarily high emotional warmth and rigid strict control","HIGH warmth but LOW demands/control — parents are indulgent and avoid confrontation","Displaying severe problematic critically chronically low warmth and completely absent control","Showing persistently problematic fundamentally unsupportive low warmth and rigid high control"], answer:1, difficulty:"easy", rationale:"Correct: (B) Permissive/indulgent parents are warm and accepting but set few limits. They avoid confrontation, make few maturity demands, and allow considerable self-regulation. Children may struggle with self-control and authority.\n\nWhy others are wrong:\n(A) High warmth + high control = authoritative parenting (optimal)\n(C) Low warmth + low control = uninvolved/neglectful parenting\n(D) Low warmth + high control = authoritarian parenting"},
        {domainId:4, q:"Selective optimization with compensation (SOC, Baltes) proposes that successful aging involves:", options:["Optimistically actively systematically consciously striving to maintain all abilities at peak maximum levels","SELECTING essential goals, OPTIMIZING resources for those goals, and COMPENSATING for losses via strategy","Significantly progressively entirely globally passively withdrawing from all meaningful social activities","Actively aggressively constantly denying and entirely thoroughly completely ignoring any cognitive decline"], answer:1, difficulty:"hard", rationale:"Correct: (B) Baltes & Baltes: older adults adapt by selecting fewer but important goals, optimizing skills/resources for those goals, and compensating for losses (e.g., Rubinstein playing fewer piano pieces, practicing them more, using contrast techniques to compensate for speed loss).\n\nWhy others are wrong:\n(A) SOC acknowledges that maintaining ALL abilities at peak is unrealistic — it's about strategic resource management\n(C) SOC involves ACTIVE selection and optimization, not complete withdrawal\n(D) SOC explicitly addresses adaptation TO decline, not ignoring it"},

        // ===== Domain 5: Assessment (5) =====
        {domainId:5, q:"The Rorschach Performance Assessment System (R-PAS) is:", options:["An entirely structured highly specific objective diagnostic clinical self-report questionnaire","A standardized administration and empirical scoring system for the Rorschach inkblot method","A highly formalized specialized comprehensive developmental cognitive intelligence assessment","A fundamental incredibly simple basic primitive introductory behavioral observation checklist"], answer:1, difficulty:"medium", rationale:"Correct: (B) R-PAS (Meyer et al., 2011): an empirically-based system for administering and scoring the Rorschach, addressing criticisms of earlier systems. It standardizes administration (optimized number of responses) and emphasizes variables with demonstrated validity.\n\nWhy others are wrong:\n(A) The Rorschach is a PERFORMANCE-based (behavioral) measure, not self-report\n(C) The Rorschach assesses personality, perception, and thought processes, not intelligence\n(D) R-PAS involves complex coding of responses, not a simple checklist"},
        {domainId:5, q:"Ceiling and floor effects in testing:", options:["Systematically consistently universally drastically improve overall psychometric test sensitivity","REDUCE the test's ability to discriminate between extreme levels of high or low examinee ability","Are universally inherently fundamentally structurally and reliably fully systematically desirable","Exclusively strictly uniquely specifically reliably occur only within formalized computerized tests"], answer:1, difficulty:"medium", rationale:"Correct: (B) Ceiling effect: too many examinees at the maximum score (test too easy for the group). Floor effect: too many at the minimum (test too hard). Both compress score variance and reduce discriminative ability.\n\nWhy others are wrong:\n(A) These effects REDUCE sensitivity by compressing scores at extremes\n(C) Ceiling/floor effects are UNDESIRABLE — they limit measurement precision\n(D) These effects can occur with any test format — paper/pencil, computerized, or performance-based"},
        {domainId:5, q:"The WISC-V (Wechsler Intelligence Scale for Children) is designed for ages:", options:["Individuals chronologically aged exactly 2 years and 6 months through 7 years and 7 months","Individuals chronologically aged exactly 6 years and 0 months through 16 years and 11 months","Individuals chronologically aged exactly 16 years and 0 months through 90 years and 11 months","Individuals chronologically aged exactly 0 years and 1 month through 3 years and 11 months"], answer:1, difficulty:"easy", rationale:"Correct: (B) WISC-V: ages 6:0-16:11. Provides FSIQ and five primary index scores: Verbal Comprehension, Visual Spatial, Fluid Reasoning, Working Memory, and Processing Speed.\n\nWhy others are wrong:\n(A) Ages 2:6-7:7 = WPPSI-IV (Wechsler Preschool and Primary Scale of Intelligence)\n(C) Ages 16-90 = WAIS-IV/V (Wechsler Adult Intelligence Scale)\n(D) Ages 0-3 = Bayley Scales of Infant and Toddler Development"},
        {domainId:5, q:"Incremental validity asks whether:", options:["A specific test instrument is fundamentally structurally internally and temporally highly reliable","A new predictor adds MEANINGFUL predictive value BEYOND what existing measures already provide","The clinical testing instrument is structurally exceptionally efficiently and easily administered","The specific clinical testing instrument is highly extraordinarily predictably notably inexpensive"], answer:1, difficulty:"hard", rationale:"Correct: (B) Incremental validity: does adding this measure improve prediction BEYOND what's already obtained? If a new test doesn't add predictive power beyond existing measures, its clinical utility is limited despite having validity.\n\nWhy others are wrong:\n(A) Reliability is a separate psychometric property from incremental validity\n(C) Ease of administration relates to practical utility, not incremental validity\n(D) Cost is an administrative concern, not a validity question"},
        {domainId:5, q:"A T-score of 70 on the MMPI-2 indicates:", options:["Perfectly normal standard healthy typical strictly universally established average functioning","A clinically significant elevation (two standard deviations substantially far above the mean)","Significantly distinctly dramatically highly markedly abnormally poor below average functioning","The strictly explicit objective precisely measured absolute diagnostic basic raw score equals 70"], answer:1, difficulty:"medium", rationale:"Correct: (B) T-scores have M = 50, SD = 10. T = 70 = 2 SDs above the mean, which on the MMPI-2 is the typical threshold for clinical significance (suggesting the scale content is being endorsed at a clinically meaningful level).\n\nWhy others are wrong:\n(A) Average = T-score of 50 (± 10)\n(C) Below average would be T < 40 (more than 1 SD below mean)\n(D) T-scores are standardized scores derived FROM raw scores — they're not the same as raw scores"},

        // ===== Domain 6: Treatment (5) =====
        {domainId:6, q:"Exposure and response prevention (ERP) is the gold-standard treatment for:", options:["Severe persistent chronic pervasive major unipolar depressive affective disorders","Obsessive-compulsive disorder characterized by severe intrusive repetitive rituals","Attention deficit hyperactivity disorder featuring extreme severe high impulsivity","Significant severe profound generalized early pervasive intellectual disability"], answer:1, difficulty:"easy", rationale:"Correct: (B) ERP for OCD: expose the client to anxiety-provoking obsessional stimuli while PREVENTING the compulsive ritual (response prevention). This breaks the reinforcement cycle — anxiety naturally habituates without the compulsions.\n\nWhy others are wrong:\n(A) Depression → CBT, behavioral activation, SSRIs, or their combination\n(C) ADHD → stimulant medication and behavioral interventions\n(D) Intellectual disability → habilitation, skills training, environmental supports"},
        {domainId:6, q:"Paradoxical intention (Frankl) involves:", options:["Consistently permanently structurally uniformly unconditionally agreeing with the specific client","Instructing the client to intentionally engage in the feared symptom to reduce anticipatory fear","Deeply actively formally comprehensively fundamentally rigidly interpreting the unconscious psyche","Exclusively strictly comprehensively uniquely solely reliably utilizing pure behavioral techniques"], answer:1, difficulty:"medium", rationale:"Correct: (B) Frankl's paradoxical intention: the client deliberately tries to produce or exaggerate the symptom (e.g., trying to stay awake for insomnia, trying to tremble for anxiety). This removes anticipatory anxiety and often eliminates the symptom.\n\nWhy others are wrong:\n(A) Paradoxical intention is a specific technique, not unconditional agreement\n(C) While Frankl's logotherapy has existential roots, paradoxical intention is a behavioral-existential technique\n(D) Paradoxical intention bridges behavioral and existential traditions — it's not purely behavioral"},
        {domainId:6, q:"The stages of change model (Prochaska & DiClemente) includes:", options:["Only two distinctly structurally fundamentally mutually exclusive isolated specific defined stages","Precontemplation, contemplation, preparation, action, and maintenance cognitive behavioral stages","Strictly uniquely exclusively solely entirely formally focusing solely upon the action phase itself","A perfectly completely thoroughly strictly purely formally reliably linear non-relapsing progression"], answer:1, difficulty:"easy", rationale:"Correct: (B) Transtheoretical model: five stages — precontemplation (not ready), contemplation (considering change), preparation (planning), action (actively changing), maintenance (sustaining change). Relapse can occur at any point.\n\nWhy others are wrong:\n(A) There are five (sometimes six, including termination) stages, not two\n(C) Action is ONE of five stages — and interventions should match the client's current stage\n(D) The model explicitly includes the possibility of relapse and cycling between stages"},
        {domainId:6, q:"Interpersonal therapy (IPT) focuses primarily on:", options:["Deeply strictly repressed fiercely firmly rigid deep unconscious intense childhood psychosexual conflicts","Current interpersonal problems: grief, role disputes, role transitions, and interpersonal deficits","Exclusively uniquely specifically thoroughly exclusively upon distorted flawed rigid cognitive patterns","Rigid uniquely structural specific formal explicitly highly quantifiable strict behavioral contingencies"], answer:1, difficulty:"medium", rationale:"Correct: (B) IPT (Klerman & Weissman): time-limited (~16 sessions) treatment for depression focusing on four problem areas — complicated grief, role disputes (interpersonal conflicts), role transitions (life changes), and interpersonal deficits (social skill deficits).\n\nWhy others are wrong:\n(A) IPT is HERE-AND-NOW focused on current relationships, not childhood unconscious material\n(C) Cognitive distortions = CBT focus; IPT targets interpersonal patterns\n(D) Behavioral contingencies = behavioral therapy; IPT focuses on relational dynamics"},
        {domainId:6, q:"Thought stopping is a technique where:", options:["The clinical practitioner formally unilaterally abruptly constantly actively interrupts the session","The client learns to interrupt intrusive thoughts by saying 'STOP' and redirecting their attention","All spontaneous mental cognition is formally fully permanently strictly abruptly completely stopped","Exclusively strictly solely uniquely only highly profoundly incredibly positive thoughts are allowed"], answer:1, difficulty:"easy", rationale:"Correct: (B) Thought stopping: when an unwanted thought occurs, the client shouts 'STOP!' (initially aloud, then subvocally), then redirects attention to a neutral or positive thought. Simple but increasingly considered less effective than acceptance-based approaches.\n\nWhy others are wrong:\n(A) The CLIENT interrupts their own thoughts, not the therapist interrupting the session\n(C) Only INTRUSIVE/unwanted thoughts are targeted — normal thinking continues\n(D) The technique is about interrupting unwanted thoughts, not filtering all thought content"},

        // ===== Domain 8: Ethics (5) =====
        {domainId:8, q:"Bartering (accepting goods/services instead of payment) is:", options:["Always inherently permanently rigorously universally categorically legally ethically entirely prohibited","Not inherently unethical but restricted when clinically contraindicated or inherently exploitative","Always universally broadly positively fully explicitly enthusiastically reliably actively encouraged","Explicitly structurally universally strictly fundamentally unequivocally fully required in rural areas"], answer:1, difficulty:"medium", rationale:"Correct: (B) Standard 6.05: bartering is permissible ONLY when (1) it's not clinically contraindicated, (2) it's not exploitative, and (3) there's a clear agreement. It's most acceptable in rural/underserved areas where it's common practice.\n\nWhy others are wrong:\n(A) Bartering isn't absolutely prohibited — it's permitted under specific conditions\n(C) Bartering is approached with CAUTION, not encouraged — risks include exploitation and role confusion\n(D) While more common in rural areas, it's not required anywhere"},
        {domainId:8, q:"The APA Ethics Code's aspiration principles are:", options:["Strict rigidly explicit objective strictly explicit formally completely highly enforceable standards","Aspirational goals guiding psychologists toward the highest professional ideals—not fully enforceable","Explicitly structurally strictly uniformly completely legally strictly legally binding in all territories","Mechanically structurally completely thoroughly entirely virtually perfectly identical to standards"], answer:1, difficulty:"easy", rationale:"Correct: (B) The five General Principles (A-E: Beneficence/Nonmaleficence, Fidelity/Responsibility, Integrity, Justice, Respect) are ASPIRATIONAL — they guide professional conduct but violations do not result in sanctions. Only the STANDARDS are enforceable.\n\nWhy others are wrong:\n(A) Principles are aspirational; STANDARDS (numbered sections) are enforceable\n(C) Aspirational principles are not legally binding — they represent ideals\n(D) Principles and standards are different sections with different purposes and enforceability"},
        {domainId:8, q:"When a psychologist receives a subpoena for client records, they should:", options:["Immediately rapidly universally extensively structurally thoroughly formally release all existing records","Contact the client, attempt to formally assert privilege if legally applicable, and seek an explicit order","Rapidly completely fully permanently entirely systematically securely physically destroy all clinical records","Unilaterally completely actively entirely uniformly thoroughly structurally definitively ignore the subpoena"], answer:1, difficulty:"hard", rationale:"Correct: (B) A subpoena is a REQUEST, not a court order. The psychologist should: (1) notify the client, (2) attempt to assert privilege, (3) consult legal counsel, (4) limit disclosure to the minimum necessary. A court ORDER compels compliance; a subpoena alone may not.\n\nWhy others are wrong:\n(A) Immediate release violates confidentiality and the minimum necessary standard\n(C) Record destruction could constitute obstruction of justice and violates record-keeping standards\n(D) Ignoring a subpoena entirely could result in contempt proceedings"},
        {domainId:8, q:"The Goldwater Rule (in psychiatry/psychology) refers to:", options:["A specific structured rigid formal legally mandated intensely scrutinized corporate financial regulatory standard","The ethical principle that professionals should avoid offering opinions on public figures they have not examined","A specific extensively validated empirical clinical strict mandatory psychological medical treatment guideline","A specific profoundly rigorous highly standardized fully peer-reviewed advanced global research methodology"], answer:1, difficulty:"hard", rationale:"Correct: (B) Named after the 1964 incident when psychiatrists publicly diagnosed Barry Goldwater. Section 7.3 of the APA Psychiatry Ethics Code (and analogous APA Psychology positions) states professionals shouldn't render diagnoses of individuals not personally examined.\n\nWhy others are wrong:\n(A) It's an ethical principle about public diagnostic statements, not financial regulation\n(C) It's about the ethics of public statements, not a treatment guideline\n(D) It's an ethics rule, not a research methodology"},
        {domainId:8, q:"Principle A (Beneficence and Nonmaleficence) directs psychologists to:", options:["Strictly explicitly consistently uniquely and exclusively constantly focus upon direct financial gain","Actively strive to directly constructively benefit clients and take extreme care to do absolutely no harm","Exclusively explicitly strictly completely rigorously unequivocally conduct systematic peer research","Actively fundamentally formally deliberately carefully entirely constantly avoid all professional relations"], answer:1, difficulty:"easy", rationale:"Correct: (B) Principle A: psychologists strive to benefit clients and minimize harm. They guard against personal, financial, social, organizational, and political factors that might lead to misuse of their influence.\n\nWhy others are wrong:\n(A) Financial gain is secondary to client welfare — Principle A prioritizes beneficence\n(C) Principle A applies to ALL professional activities, not just research\n(D) Being helpful requires professional relationships — avoidance would contradict the principle"}
    ];

    batch20.forEach(q => {
        const domain = EPPPData.domains.find(d => d.id === q.domainId);
        if (domain) {
            domain.questions.push({
                q: q.q, options: q.options, answer: q.answer,
                difficulty: q.difficulty, rationale: q.rationale,
                domainId: q.domainId, domainName: domain.name
            });
        }
    });

    console.log(`PasstheEPPP: Loaded ${batch20.length} additional questions (batch 20 — enhanced rationales).`);
})();
